import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Edit, Trash2, Search, User } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtists = () => {
  const [artists, setArtists] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchArtists = async () => {
    try {
      const res = await AdminService.getAllArtists();
      setArtists(Array.isArray(res.data) ? res.data : res.data.artists || []);
    } catch (err) { toast.error("Archive Retrieval Failure"); }
  };

  useEffect(() => { fetchArtists(); }, []);

  const filtered = artists.filter(a => a.Full_Name?.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Artists <span className="text-primary">Registry</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Core Archive</p>
        </div>
        <Link to="/admin/artists/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-all shadow-xl">
          <Plus size={16} /> Register Artist
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
        <input placeholder="Search registry..." className="w-full pl-12 pr-4 py-4 bg-white rounded-2xl border border-gray-100 outline-none focus:ring-2 focus:ring-primary font-bold shadow-sm" onChange={(e) => setSearch(e.target.value)} />
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filtered.map((artist) => (
          <div key={artist._id} className="bg-white p-6 rounded-[1.5rem] flex items-center justify-between shadow-sm border border-gray-50 hover:border-primary transition-all group">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center text-gray-400 group-hover:bg-primary/10 group-hover:text-primary transition-colors"><User size={20} /></div>
              <div>
                <h4 className="font-black uppercase text-sm italic">{artist.Full_Name}</h4>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{artist.Artist_ID}</p>
              </div>
            </div>
            <div className="flex gap-2">
              <Link to={`/admin/artists/edit/${artist.Artist_ID}`} className="p-3 bg-gray-50 rounded-xl hover:bg-black hover:text-white transition-all"><Edit size={16} /></Link>
              <button className="p-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={16} /></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
